starterCode.javascript:
function calculate<T>(numbers: T[], operation: string): any {
  if (operation === 'add') {
    return numbers.reduce((a, b) => a + b);
  }
  if (operation === 'subtract') {
    return numbers.reduce((a, b) => a - b);
  }
  if (operation === 'multiply') {
    return numbers.reduce((a, b) => a * b);
  }
  if (operation === 'divide') {
    return numbers.reduce((a, b) => a / b);
  }
}

